import React, { useState, useEffect } from "react";

const PdfViewer = () => {
  const [pdfList, setPdfList] = useState([]);
  const [selectedPdf, setSelectedPdf] = useState("");

  // Fetch the list of PDFs from your backend when the component mounts
  useEffect(() => {
    const fetchPdfList = async () => {
      try {
        const response = await fetch("http://localhost:8000/pdfs");
        const data = await response.json();
        setPdfList(data.pdf_files || []);
      } catch (error) {
        console.error("Error fetching PDFs:", error);
      }
    };

    fetchPdfList();
  }, []);

  // Handle PDF selection from the dropdown
  const handlePdfSelection = (event) => {
    const selected = event.target.value;
    setSelectedPdf(selected);
  };

  return (
    <div style={{ display: "flex", height: "100vh" }}>
      {/* Left Panel: Contains the PDF selection dropdown */}
      <div
        style={{
          width: "300px",
          padding: "1rem",
          borderRight: "1px solid #ccc",
          boxSizing: "border-box",
        }}
      >
        <h3>Select PDF:</h3>
        <select
          value={selectedPdf}
          onChange={handlePdfSelection}
          style={{ width: "100%", padding: "0.5rem" }}
        >
          <option value="">-- Select a PDF --</option>
          {pdfList.map((pdf) => (
            <option key={pdf} value={pdf}>
              {pdf}
            </option>
          ))}
        </select>
      </div>

      {/* Right Panel: Blank until a PDF is selected */}
      <div
        style={{
          flex: 1,
          padding: "1rem",
          boxSizing: "border-box",
        }}
      >
        {selectedPdf ? (
          <object
            data={`http://localhost:8000/pdfs/${selectedPdf}`}
            type="application/pdf"
            width="100%"
            height="800px"
            style={{ border: "none" }}
          >
            <p>Unable to display PDF file.</p>
          </object>
        ) : (
          // Blank panel (with a minimum height for layout consistency)
          <div style={{ minHeight: "800px" }}></div>
        )}
      </div>
    </div>
  );
};

export default PdfViewer;
